(482,'species.created',1,'petsona.helpcare@gmail.com','127.0.0.1','Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/147.0.0.0 Safari/537.36','2026-04-24 22:09:30','{\"changes\": {\"name\": {\"old\": null, \"new\": \"Dog\"}, \"description\": {\"old\": null, \"new\": \"A dog (Canis lupus familiaris) is a domesticated mammal descended from wolves and valued for its intelligence, loyalty, and adaptability. Dogs have a powerful sense of smell, strong social instincts, and the ability to learn commands and tasks. They vary widely in size and behavior across breeds and serve roles as companions, workers, and protectors.\"}, \"icon\": {\"old\": null, \"new\": \"fa-solid fa-dog\"}, \"requires_exercise\": {\"old\": null, \"new\": true}, \"requires_training\": {\"old\": null, \"new\": true}, \"requires_grooming\": {\"old\": null, \"new\": true}, \"requires_enclosure\": {\"old\": null, \"new\": false}, \"predatory_species\": {\"old\": null, \"new\": false}, \"fragile_species\": {\"old\": null, \"new\": false}, \"beginner_friendly\": {\"old\": null, \"new\": true}, \"requires_permit\": {\"old\": null, \"new\": false}, \"special_vet_required\": {\"old\": null, \"new\": false}, \"has_breed\": {\"old\": null, \"new\": true}, \"abandonment_risk_level\": {\"old\": null, \"new\": \"High\"}, \"ethical_notes\": {\"old\": null, \"new\": \"Dogs should be obtained from responsible breeders or adopted from shelters to avoid supporting puppy mills. Ensure proper vaccination, regular veterinary care, and humane training methods. Avoid neglect, chaining, or abandonment. Spaying/neutering is encouraged to control overpopulation and improve health.\"}, \"image_url\": {\"old\": null, \"new\": \"uploads/species/Dog_Species.png\"}}, \"species_id\": 58, \"name\": \"Dog\"}',NULL),
(483,'species.created',1,'petsona.helpcare@gmail.com','127.0.0.1','Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/147.0.0.0 Safari/537.36','2026-04-24 22:11:23','{\"changes\": {\"name\": {\"old\": null, \"new\": \"Cat\"}, \"description\": {\"old\": null, \"new\": \"A **cat** (*Felis catus*) is a small domesticated carnivorous mammal known for its independence, agility, and strong hunting instincts. Cats have sharp senses, flexible bodies, and retractable claws. They are popular companion animals due to their affectionate yet low-maintenance nature, often forming bonds with humans while maintaining independent behavior.\"}, \"icon\": {\"old\": null, \"new\": \"fa-solid fa-cat\"}, \"requires_exercise\": {\"old\": null, \"new\": true}, \"requires_training\": {\"old\": null, \"new\": false}, \"requires_grooming\": {\"old\": null, \"new\": true}, \"requires_enclosure\": {\"old\": null, \"new\": false}, \"predatory_species\": {\"old\": null, \"new\": false}, \"fragile_species\": {\"old\": null, \"new\": false}, \"beginner_friendly\": {\"old\": null, \"new\": true}, \"requires_permit\": {\"old\": null, \"new\": false}, \"special_vet_required\": {\"old\": null, \"new\": false}, \"has_breed\": {\"old\": null, \"new\": true}, \"abandonment_risk_level\": {\"old\": null, \"new\": \"High\"}, \"ethical_notes\": {\"old\": null, \"new\": \"Cats should be adopted or sourced from responsible breeders, not uncontrolled breeding or illegal trade. Spaying/neutering is essential to prevent overpopulation. Provide proper nutrition, vaccinations, and safe indoor/outdoor balance to reduce risks like injury, disease, or wildlife impact. Avoid neglect or abandonment, as cats rely on humans for long-term care and welfare.\"}, \"image_url\": {\"old\": null, \"new\": \"uploads/species/cat_species.png\"}}, \"species_id\": 59, \"name\": \"Cat\"}',NULL),
(484,'species.created',1,'petsona.helpcare@gmail.com','127.0.0.1','Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/147.0.0.0 Safari/537.36','2026-04-24 22:15:15','{\"changes\": {\"name\": {\"old\": null, \"new\": \"Parakeet\"}, \"description\": {\"old\": null, \"new\": \"A parakeet (budgerigar) (Melopsittacus undulatus) is a small, intelligent parrot native to Australia. It is known for its bright colors, playful behavior, and ability to mimic sounds. Parakeets are social birds that thrive in pairs or small groups and can bond strongly with humans when properly tamed.\"}, \"icon\": {\"old\": null, \"new\": \"fa-solid fa-dove\"}, \"requires_exercise\": {\"old\": null, \"new\": false}, \"requires_training\": {\"old\": null, \"new\": false}, \"requires_grooming\": {\"old\": null, \"new\": false}, \"requires_enclosure\": {\"old\": null, \"new\": false}, \"predatory_species\": {\"old\": null, \"new\": false}, \"fragile_species\": {\"old\": null, \"new\": false}, \"beginner_friendly\": {\"old\": null, \"new\": true}, \"requires_permit\": {\"old\": null, \"new\": false}, \"special_vet_required\": {\"old\": null, \"new\": false}, \"has_breed\": {\"old\": null, \"new\": true}, \"abandonment_risk_level\": {\"old\": null, \"new\": \"Medium\"}, \"ethical_notes\": {\"old\": null, \"new\": \"Parakeets should be sourced from responsible breeders or pet shops, avoiding illegal wild capture. They need social interaction, mental stimulation, and proper cage space to prevent stress and feather plucking. Keeping them in pairs improves welfare. Avoid neglect, isolation, or small cages. Regular vet checks and a balanced diet are essential for long-term health.\"}, \"image_url\": {\"old\": null, \"new\": \"uploads/species/Colorful_parakeet_lineup_on_beige_sofa.png\"}}, \"species_id\": 60, \"name\": \"Parakeet\"}',NULL),
(485,'species.created',1,'petsona.helpcare@gmail.com','127.0.0.1','Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/147.0.0.0 Safari/537.36','2026-04-24 22:16:44','{\"changes\": {\"name\": {\"old\": null, \"new\": \"Cockateil\"}, \"description\": {\"old\": null, \"new\": \"A cockatiel (Nymphicus hollandicus) is a small, friendly parrot native to Australia. It is known for its distinctive crest, whistling ability, and affectionate nature. Cockatiels are social birds that bond closely with their owners and enjoy interaction, toys, and gentle handling.\"}, \"icon\": {\"old\": null, \"new\": \"fa-solid fa-dove\"}, \"requires_exercise\": {\"old\": null, \"new\": false}, \"requires_training\": {\"old\": null, \"new\": false}, \"requires_grooming\": {\"old\": null, \"new\": false}, \"requires_enclosure\": {\"old\": null, \"new\": false}, \"predatory_species\": {\"old\": null, \"new\": false}, \"fragile_species\": {\"old\": null, \"new\": false}, \"beginner_friendly\": {\"old\": null, \"new\": true}, \"requires_permit\": {\"old\": null, \"new\": false}, \"special_vet_required\": {\"old\": null, \"new\": false}, \"has_breed\": {\"old\": null, \"new\": false}, \"abandonment_risk_level\": {\"old\": null, \"new\": \"Medium\"}, \"ethical_notes\": {\"old\": null, \"new\": \"Cockatiels should be obtained from responsible breeders or reputable pet shops, avoiding wild capture. They need daily social interaction, mental stimulation, and adequate cage space. Isolation can cause stress or feather plucking. Regular vet care, a balanced diet, and safe handling are essential. Never neglect or release them into the wild, as they depend on human care for survival.\"}, \"image_url\": {\"old\": null, \"new\": \"uploads/species/A_vibrant_cockatiel_gathering_in_a_living_room.png\"}}, \"species_id\": 61, \"name\": \"Cockateil\"}',NULL),
(486,'species.created',1,'petsona.helpcare@gmail.com','127.0.0.1','Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/147.0.0.0 Safari/537.36','2026-04-24 22:18:08','{\"changes\": {\"name\": {\"old\": null, \"new\": \"Bettafish\"}, \"description\": {\"old\": null, \"new\": \"A betta fish (Betta splendens), also called Siamese fighting fish, is a small freshwater fish native to Southeast Asia. It is known for its vibrant colors, flowing fins, and territorial behavior, especially among males. Bettas are popular aquarium pets due to their beauty and ability to breathe surface air using a labyrinth organ.\"}, \"icon\": {\"old\": null, \"new\": \"fa-solid fa-fish\"}, \"requires_exercise\": {\"old\": null, \"new\": false}, \"requires_training\": {\"old\": null, \"new\": false}, \"requires_grooming\": {\"old\": null, \"new\": false}, \"requires_enclosure\": {\"old\": null, \"new\": false}, \"predatory_species\": {\"old\": null, \"new\": false}, \"fragile_species\": {\"old\": null, \"new\": false}, \"beginner_friendly\": {\"old\": null, \"new\": false}, \"requires_permit\": {\"old\": null, \"new\": false}, \"special_vet_required\": {\"old\": null, \"new\": false}, \"has_breed\": {\"old\": null, \"new\": false}, \"abandonment_risk_level\": {\"old\": null, \"new\": \"Low\"}, \"ethical_notes\": {\"old\": null, \"new\": \"Betta fish should never be kept in small bowls; they require filtered, cycled tanks for proper health. Avoid overbreeding and ensure humane breeding practices, as males are often separated due to aggression. Poor water quality and overcrowding are major welfare issues. Responsible ownership includes proper tank size, filtration, and temperature control.\"}, \"image_url\": {\"old\": null, \"new\": \"uploads/species/Colorful_betta_fish_collection_arrangement.png\"}}, \"species_id\": 62, \"name\": \"Bettafish\"}',NULL),
(487,'species.created',1,'petsona.helpcare@gmail.com','127.0.0.1','Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/147.0.0.0 Safari/537.36','2026-04-24 22:19:13','{\"changes\": {\"name\": {\"old\": null, \"new\": \"Goldfish\"}, \"description\": {\"old\": null, \"new\": \"A goldfish (Carassius auratus) is a freshwater ornamental fish originally domesticated in China. It is known for its bright colors, flowing fins, and calm temperament. Goldfish are hardy and can live for many years when given proper tank size, clean water, and good nutrition.\"}, \"icon\": {\"old\": null, \"new\": \"fa-solid fa-fish\"}, \"requires_exercise\": {\"old\": null, \"new\": false}, \"requires_training\": {\"old\": null, \"new\": false}, \"requires_grooming\": {\"old\": null, \"new\": false}, \"requires_enclosure\": {\"old\": null, \"new\": false}, \"predatory_species\": {\"old\": null, \"new\": false}, \"fragile_species\": {\"old\": null, \"new\": false}, \"beginner_friendly\": {\"old\": null, \"new\": false}, \"requires_permit\": {\"old\": null, \"new\": false}, \"special_vet_required\": {\"old\": null, \"new\": false}, \"has_breed\": {\"old\": null, \"new\": true}, \"abandonment_risk_level\": {\"old\": null, \"new\": \"Medium\"}, \"ethical_notes\": {\"old\": null, \"new\": \"Goldfish should never be kept in small bowls; they require spacious, filtered, and well-oxygenated tanks or ponds. Overcrowding and poor water quality are major welfare issues. Responsible ownership includes proper tank cycling, adequate space, and long-term commitment, as goldfish can live over 10\\u201315 years when properly cared for.\"}, \"image_url\": {\"old\": null, \"new\": \"uploads/species/Colorful_display_of_goldfish_varieties.png\"}}, \"species_id\": 63, \"name\": \"Goldfish\"}',NULL),
(488,'species.created',1,'petsona.helpcare@gmail.com','127.0.0.1','Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/147.0.0.0 Safari/537.36','2026-04-24 22:20:45','{\"changes\": {\"name\": {\"old\": null, \"new\": \"Tetra\"}, \"description\": {\"old\": null, \"new\": \"A tetra refers to a group of small freshwater schooling fish from the Characidae family, popular in aquariums. They are known for their bright colors, peaceful nature, and active swimming behavior. Tetras thrive in groups and are commonly kept in community tanks.\"}, \"icon\": {\"old\": null, \"new\": \"fa-solid fa-fish\"}, \"requires_exercise\": {\"old\": null, \"new\": false}, \"requires_training\": {\"old\": null, \"new\": false}, \"requires_grooming\": {\"old\": null, \"new\": false}, \"requires_enclosure\": {\"old\": null, \"new\": false}, \"predatory_species\": {\"old\": null, \"new\": false}, \"fragile_species\": {\"old\": null, \"new\": false}, \"beginner_friendly\": {\"old\": null, \"new\": false}, \"requires_permit\": {\"old\": null, \"new\": false}, \"special_vet_required\": {\"old\": null, \"new\": false}, \"has_breed\": {\"old\": null, \"new\": false}, \"abandonment_risk_level\": {\"old\": null, \"new\": \"Low\"}, \"ethical_notes\": {\"old\": null, \"new\": \"Tetras should be kept in groups (schooling fish) to prevent stress and unnatural behavior. They require clean, stable water conditions and proper filtration. Avoid overcrowding and sudden water changes. Responsible care includes maintaining a balanced community tank and not mixing them with aggressive species.\"}, \"image_url\": {\"old\": null, \"new\": \"uploads/species/Colorful_tetra_fish_display_on_steps.png\"}}, \"species_id\": 64, \"name\": \"Tetra\"}',NULL),
(489,'species.created',1,'petsona.helpcare@gmail.com','127.0.0.1','Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/147.0.0.0 Safari/537.36','2026-04-24 22:22:17','{\"changes\": {\"name\": {\"old\": null, \"new\": \"Arowana\"}, \"description\": {\"old\": null, \"new\": \"An arowana (Osteoglossum / Scleropages species) is a large, predatory freshwater fish known for its elongated body, metallic scales, and surface-swimming behavior. Often called a \\u201cdragon fish,\\u201d it is prized in aquariums and considered a symbol of luck and prosperity in some Asian cultures. Arowanas require very large tanks and long-term commitment.\"}, \"icon\": {\"old\": null, \"new\": \"fa-solid fa-fish\"}, \"requires_exercise\": {\"old\": null, \"new\": false}, \"requires_training\": {\"old\": null, \"new\": false}, \"requires_grooming\": {\"old\": null, \"new\": false}, \"requires_enclosure\": {\"old\": null, \"new\": false}, \"predatory_species\": {\"old\": null, \"new\": false}, \"fragile_species\": {\"old\": null, \"new\": false}, \"beginner_friendly\": {\"old\": null, \"new\": false}, \"requires_permit\": {\"old\": null, \"new\": false}, \"special_vet_required\": {\"old\": null, \"new\": false}, \"has_breed\": {\"old\": null, \"new\": true}, \"abandonment_risk_level\": {\"old\": null, \"new\": \"High\"}, \"ethical_notes\": {\"old\": null, \"new\": \"Arowanas should only be kept by experienced aquarists with large, properly filtered tanks or ponds. Poor housing in small aquariums leads to stress, deformities, and health issues. Some species are protected or regulated, requiring legal permits. Responsible ownership includes ethical sourcing, long-term care planning, and avoiding illegal wildlife trade.\"}, \"image_url\": {\"old\": null, \"new\": \"uploads/species/Colorful_collection_of_arowana_fish.png\"}}, \"species_id\": 65, \"name\": \"Arowana\"}',NULL),
(490,'species.created',1,'petsona.helpcare@gmail.com','127.0.0.1','Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/147.0.0.0 Safari/537.36','2026-04-24 22:23:25','{\"changes\": {\"name\": {\"old\": null, \"new\": \"Turtle\"}, \"description\": {\"old\": null, \"new\": \"A turtle is a reptile with a hard protective shell that lives in water, land, or both depending on the species. Common pet turtles in the Philippines are freshwater types like red-eared sliders. They are slow-moving, long-lived animals that require clean water, proper heat, and a balanced diet.\"}, \"icon\": {\"old\": null, \"new\": \"fa-solid fa-dragon\"}, \"requires_exercise\": {\"old\": null, \"new\": false}, \"requires_training\": {\"old\": null, \"new\": false}, \"requires_grooming\": {\"old\": null, \"new\": false}, \"requires_enclosure\": {\"old\": null, \"new\": false}, \"predatory_species\": {\"old\": null, \"new\": false}, \"fragile_species\": {\"old\": null, \"new\": false}, \"beginner_friendly\": {\"old\": null, \"new\": false}, \"requires_permit\": {\"old\": null, \"new\": false}, \"special_vet_required\": {\"old\": null, \"new\": false}, \"has_breed\": {\"old\": null, \"new\": true}, \"abandonment_risk_level\": {\"old\": null, \"new\": \"High\"}, \"ethical_notes\": {\"old\": null, \"new\": \"Turtles should never be kept in small containers or bowls. They require a properly filtered aquatic tank with a dry basking area and UVB lighting for shell health. Many pet turtles are abandoned when they grow large. Responsible ownership includes long-term commitment, proper filtration, and preventing release into local ecosystems, which can harm native wildlife.\"}, \"image_url\": {\"old\": null, \"new\": \"uploads/species/Turtles_displayed_on_fabric-covered_steps.png\"}}, \"species_id\": 66, \"name\": \"Turtle\"}',NULL),
(491,'species.created',1,'petsona.helpcare@gmail.com','127.0.0.1','Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/147.0.0.0 Safari/537.36','2026-04-24 22:24:17','{\"changes\": {\"name\": {\"old\": null, \"new\": \"Tortoise\"}, \"description\": {\"old\": null, \"new\": \"A tortoise is a land-dwelling reptile known for its heavy dome-shaped shell, slow movement, and long lifespan. Unlike turtles, tortoises live mostly on land and are herbivores, feeding on grasses, leaves, and vegetables. They require warm environments, proper hydration, and outdoor space when possible.\"}, \"icon\": {\"old\": null, \"new\": \"fa-solid fa-dragon\"}, \"requires_exercise\": {\"old\": null, \"new\": false}, \"requires_training\": {\"old\": null, \"new\": false}, \"requires_grooming\": {\"old\": null, \"new\": false}, \"requires_enclosure\": {\"old\": null, \"new\": false}, \"predatory_species\": {\"old\": null, \"new\": false}, \"fragile_species\": {\"old\": null, \"new\": false}, \"beginner_friendly\": {\"old\": null, \"new\": false}, \"requires_permit\": {\"old\": null, \"new\": false}, \"special_vet_required\": {\"old\": null, \"new\": false}, \"has_breed\": {\"old\": null, \"new\": true}, \"abandonment_risk_level\": {\"old\": null, \"new\": \"High\"}, \"ethical_notes\": {\"old\": null, \"new\": \"Tortoises should never be taken from the wild or purchased from illegal sources. Many species are protected under wildlife laws and may require permits. They need proper UVB sunlight, calcium-rich diet, and spacious outdoor enclosures. Poor care can cause shell deformities and illness. Responsible ownership requires lifelong commitment due to their very long lifespan.\"}, \"image_url\": {\"old\": null, \"new\": \"uploads/species/Tortoise_variety_on_tiered_display.png\"}}, \"species_id\": 67, \"name\": \"Tortoise\"}',NULL),
(492,'species.created',1,'petsona.helpcare@gmail.com','127.0.0.1','Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/147.0.0.0 Safari/537.36','2026-04-24 22:25:50','{\"changes\": {\"name\": {\"old\": null, \"new\": \"Gecko\"}, \"description\": {\"old\": null, \"new\": \"A gecko is a small to medium-sized lizard found in tropical and warm regions, including the Philippines. It is known for its ability to climb walls and ceilings using specialized toe pads. Many geckos are nocturnal, insect-eating reptiles that are popular as low-maintenance exotic pets.\"}, \"icon\": {\"old\": null, \"new\": \"fa-solid fa-dragon\"}, \"requires_exercise\": {\"old\": null, \"new\": false}, \"requires_training\": {\"old\": null, \"new\": false}, \"requires_grooming\": {\"old\": null, \"new\": false}, \"requires_enclosure\": {\"old\": null, \"new\": false}, \"predatory_species\": {\"old\": null, \"new\": false}, \"fragile_species\": {\"old\": null, \"new\": false}, \"beginner_friendly\": {\"old\": null, \"new\": false}, \"requires_permit\": {\"old\": null, \"new\": false}, \"special_vet_required\": {\"old\": null, \"new\": false}, \"has_breed\": {\"old\": null, \"new\": true}, \"abandonment_risk_level\": {\"old\": null, \"new\": \"Medium\"}, \"ethical_notes\": {\"old\": null, \"new\": \"Geckos should be captive-bred and never taken from the wild. They require proper heat, humidity, and live insect diets such as crickets or mealworms. Poor enclosure conditions can lead to stress and illness. Responsible ownership includes providing a suitable terrarium, avoiding wild capture, and ensuring ethical sourcing from breeders or reputable pet shops.\"}, \"image_url\": {\"old\": null, \"new\": \"uploads/species/Colorful_geckos_on_tiered_steps.png\"}}, \"species_id\": 68, \"name\": \"Gecko\"}',NULL),
(493,'species.created',1,'petsona.helpcare@gmail.com','127.0.0.1','Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/147.0.0.0 Safari/537.36','2026-04-24 22:28:32','{\"changes\": {\"name\": {\"old\": null, \"new\": \"Ball Python\"}, \"description\": {\"old\": null, \"new\": \"A ball python (Python regius) is a small, non-venomous constrictor snake native to Africa. It is named for its behavior of curling into a tight \\u201cball\\u201d when stressed. Ball pythons are popular exotic pets due to their calm temperament, manageable size, and relatively simple care compared to other snakes.\"}, \"icon\": {\"old\": null, \"new\": \"fa-solid fa-dragon\"}, \"requires_exercise\": {\"old\": null, \"new\": false}, \"requires_training\": {\"old\": null, \"new\": false}, \"requires_grooming\": {\"old\": null, \"new\": false}, \"requires_enclosure\": {\"old\": null, \"new\": true}, \"predatory_species\": {\"old\": null, \"new\": false}, \"fragile_species\": {\"old\": null, \"new\": false}, \"beginner_friendly\": {\"old\": null, \"new\": false}, \"requires_permit\": {\"old\": null, \"new\": false}, \"special_vet_required\": {\"old\": null, \"new\": true}, \"has_breed\": {\"old\": null, \"new\": false}, \"abandonment_risk_level\": {\"old\": null, \"new\": \"High\"}, \"ethical_notes\": {\"old\": null, \"new\": \"Ball pythons should always be captive-bred, not wild-caught, to avoid ecological harm and stress-related health issues. They require controlled heat, humidity, and secure enclosures to prevent escape and illness. Feeding must be humane (properly prepared frozen-thawed rodents preferred). Responsible ownership includes long-term commitment and proper understanding of reptile care.\"}, \"image_url\": {\"old\": null, \"new\": \"uploads/species/Colorful_ball_pythons_on_steps.png\"}}, \"species_id\": 69, \"name\": \"Ball Python\"}',NULL),
(494,'species.updated',1,'petsona.helpcare@gmail.com','127.0.0.1','Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/147.0.0.0 Safari/537.36','2026-04-24 22:47:23','{\"changes\": {\"requires_enclosure\": {\"old\": false, \"new\": true}, \"predatory_species\": {\"old\": false, \"new\": true}, \"special_vet_required\": {\"old\": false, \"new\": true}, \"ethical_notes\": {\"old\": \"Arowanas should only be kept by experienced aquarists with large, properly filtered tanks or ponds. Poor housing in small aquariums leads to stress, deformities, and health issues. Some species are protected or regulated, requiring legal permits. Responsible ownership includes ethical sourcing, long-term care planning, and avoiding illegal wildlife trade.\", \"new\": \"Arowanas require large aquariums or ponds, strong filtration, and stable water conditions. Many are abandoned due to rapid growth, high cost, and space requirements. Some species are regulated or protected, requiring legal documentation. Ethical ownership includes captive-bred sourcing, avoiding illegal wildlife trade, and long-term commitment of 15\\u201320+ years.\"}}, \"species_id\": 65, \"name\": \"Arowana\"}',NULL),
(495,'species.updated',1,'petsona.helpcare@gmail.com','127.0.0.1','Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/147.0.0.0 Safari/537.36','2026-04-24 22:48:47','{\"changes\": {\"requires_grooming\": {\"old\": false, \"new\": true}, \"predatory_species\": {\"old\": false, \"new\": true}, \"ethical_notes\": {\"old\": \"Ball pythons should always be captive-bred, not wild-caught, to avoid ecological harm and stress-related health issues. They require controlled heat, humidity, and secure enclosures to prevent escape and illness. Feeding must be humane (properly prepared frozen-thawed rodents preferred). Responsible ownership includes long-term commitment and proper understanding of reptile care.\", \"new\": \"Ball pythons require precise heat, humidity, and secure enclosures to maintain health. They are often abandoned due to feeding difficulties, fear of handling, and long lifespan commitments. Captive-bred snakes are strongly recommended over wild-caught specimens. Responsible ownership includes ethical feeding practices using frozen-thawed prey and long-term care planning of 20\\u201330+ years.\"}}, \"species_id\": 69, \"name\": \"Ball Python\"}',NULL),
(496,'species.updated',1,'petsona.helpcare@gmail.com','127.0.0.1','Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/147.0.0.0 Safari/537.36','2026-04-24 22:50:29','{\"changes\": {\"requires_grooming\": {\"old\": false, \"new\": true}, \"requires_enclosure\": {\"old\": false, \"new\": true}, \"predatory_species\": {\"old\": false, \"new\": true}, \"beginner_friendly\": {\"old\": false, \"new\": true}, \"special_vet_required\": {\"old\": false, \"new\": true}, \"ethical_notes\": {\"old\": \"Betta fish should never be kept in small bowls; they require filtered, cycled tanks for proper health. Avoid overbreeding and ensure humane breeding practices, as males are often separated due to aggression. Poor water quality and overcrowding are major welfare issues. Responsible ownership includes proper tank size, filtration, and temperature control.\", \"new\": \"Betta fish require proper filtered and cycled tanks, not bowls, to maintain health. Poor water conditions are the main cause of stress and disease. Responsible care includes stable temperature, clean water, and ethical breeding practices. Bettas are often mis-sold in small containers, leading to neglect. They are hardy but still require proper aquarium setup and maintenance.\"}}, \"species_id\": 62, \"name\": \"Bettafish\"}',NULL),
(497,'species.updated',1,'petsona.helpcare@gmail.com','127.0.0.1','Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/147.0.0.0 Safari/537.36','2026-04-24 22:52:55','{\"changes\": {\"requires_training\": {\"old\": false, \"new\": true}, \"predatory_species\": {\"old\": false, \"new\": true}, \"special_vet_required\": {\"old\": false, \"new\": true}, \"ethical_notes\": {\"old\": \"Cats should be adopted or sourced from responsible breeders, not uncontrolled breeding or illegal trade. Spaying/neutering is essential to prevent overpopulation. Provide proper nutrition, vaccinations, and safe indoor/outdoor balance to reduce risks like injury, disease, or wildlife impact. Avoid neglect or abandonment, as cats rely on humans for long-term care and welfare.\", \"new\": \"Cats require responsible ownership, including spaying/neutering to control overpopulation. They should be provided proper nutrition, vaccinations, litter training, and safe indoor living to reduce risks such as disease, injury, or traffic accidents. Ethical care includes adoption from shelters or responsible breeders and avoiding neglect, abandonment, or uncontrolled breeding.\"}}, \"species_id\": 59, \"name\": \"Cat\"}',NULL),
(498,'species.updated',1,'petsona.helpcare@gmail.com','127.0.0.1','Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/147.0.0.0 Safari/537.36','2026-04-24 22:53:51','{\"changes\": {\"requires_exercise\": {\"old\": false, \"new\": true}, \"requires_training\": {\"old\": false, \"new\": true}, \"requires_grooming\": {\"old\": false, \"new\": true}, \"requires_enclosure\": {\"old\": false, \"new\": true}, \"fragile_species\": {\"old\": false, \"new\": true}, \"special_vet_required\": {\"old\": false, \"new\": true}, \"ethical_notes\": {\"old\": \"Cockatiels should be obtained from responsible breeders or reputable pet shops, avoiding wild capture. They need daily social interaction, mental stimulation, and adequate cage space. Isolation can cause stress or feather plucking. Regular vet care, a balanced diet, and safe handling are essential. Never neglect or release them into the wild, as they depend on human care for survival.\", \"new\": \"Cockatiels require daily interaction, mental stimulation, and a properly sized cage to prevent stress and behavioral issues like feather plucking. They should be sourced responsibly from breeders or reputable pet shops. A balanced diet, regular vet care, and social bonding are essential. Avoid isolation and never release them into the wild, as they are fully dependent on human care.\"}}, \"species_id\": 61, \"name\": \"Cockateil\"}',NULL),
(499,'species.updated',1,'petsona.helpcare@gmail.com','127.0.0.1','Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/147.0.0.0 Safari/537.36','2026-04-24 22:54:41','{\"changes\": {\"predatory_species\": {\"old\": false, \"new\": true}, \"special_vet_required\": {\"old\": false, \"new\": true}, \"ethical_notes\": {\"old\": \"Dogs should be obtained from responsible breeders or adopted from shelters to avoid supporting puppy mills. Ensure proper vaccination, regular veterinary care, and humane training methods. Avoid neglect, chaining, or abandonment. Spaying/neutering is encouraged to control overpopulation and improve health.\", \"new\": \"Dogs require long-term commitment, including proper training, vaccinations, exercise, and social interaction. Ethical ownership involves adoption from shelters or responsible breeders, avoiding puppy mills, and preventing neglect or abandonment. Spaying/neutering is important to control overpopulation. Dogs should never be chained or left isolated for long periods, as they are highly social animals.\"}}, \"species_id\": 58, \"name\": \"Dog\"}',NULL),
(500,'species.updated',1,'petsona.helpcare@gmail.com','127.0.0.1','Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/147.0.0.0 Safari/537.36','2026-04-24 22:56:08','{\"changes\": {\"requires_grooming\": {\"old\": false, \"new\": true}, \"requires_enclosure\": {\"old\": false, \"new\": true}, \"predatory_species\": {\"old\": false, \"new\": true}, \"fragile_species\": {\"old\": false, \"new\": true}, \"beginner_friendly\": {\"old\": false, \"new\": true}, \"special_vet_required\": {\"old\": false, \"new\": true}, \"ethical_notes\": {\"old\": \"Geckos should be captive-bred and never taken from the wild. They require proper heat, humidity, and live insect diets such as crickets or mealworms. Poor enclosure conditions can lead to stress and illness. Responsible ownership includes providing a suitable terrarium, avoiding wild capture, and ensuring ethical sourcing from breeders or reputable pet shops.\", \"new\": \"Geckos must be captive-bred and never taken from the wild to protect ecosystems. They require a properly heated and humid terrarium, along with a live insect diet. Poor enclosure setup can lead to stress, dehydration, or shedding problems. Responsible ownership includes maintaining stable habitat conditions, ethical sourcing, and avoiding wild capture or illegal trade.\"}}, \"species_id\": 68, \"name\": \"Gecko\"}',NULL),
