(508,'species.created',1,'petsona.helpcare@gmail.com','127.0.0.1','Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/147.0.0.0 Safari/537.36','2026-04-25 20:26:18','{\"changes\": {\"name\": {\"old\": null, \"new\": \"Dog\"}, \"description\": {\"old\": null, \"new\": \"Dogs are domesticated mammals known for their loyalty, intelligence, and strong bond with humans. They vary widely in size, breed, and temperament, but most are social animals that thrive on companionship, training, and routine. Dogs are often used as pets, working animals, and service companions. They require proper care, including food, exercise, grooming, and affection. With guidance, they become obedient, protective, and loving members of the family.\"}, \"icon\": {\"old\": null, \"new\": \"fa-solid fa-dog\"}, \"requires_exercise\": {\"old\": null, \"new\": true}, \"requires_training\": {\"old\": null, \"new\": true}, \"requires_grooming\": {\"old\": null, \"new\": true}, \"requires_enclosure\": {\"old\": null, \"new\": false}, \"predatory_species\": {\"old\": null, \"new\": false}, \"fragile_species\": {\"old\": null, \"new\": true}, \"beginner_friendly\": {\"old\": null, \"new\": true}, \"requires_permit\": {\"old\": null, \"new\": false}, \"special_vet_required\": {\"old\": null, \"new\": false}, \"has_breed\": {\"old\": null, \"new\": true}, \"abandonment_risk_level\": {\"old\": null, \"new\": \"Medium\"}, \"ethical_notes\": {\"old\": null, \"new\": \"Dogs require long-term commitment, daily care, exercise, and emotional attention. Many are surrendered due to unrealistic expectations or lack of training. Responsible ownership includes proper training, sterilization, and choosing a breed that matches the owner\\u2019s lifestyle.\"}, \"image_url\": {\"old\": null, \"new\": \"uploads/species/Dog_Species.png\"}}, \"species_id\": 70, \"name\": \"Dog\"}',NULL),
(509,'species.updated',1,'petsona.helpcare@gmail.com','127.0.0.1','Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/147.0.0.0 Safari/537.36','2026-04-25 20:29:52','{\"changes\": {\"fragile_species\": {\"old\": true, \"new\": false}, \"requires_permit\": {\"old\": null, \"new\": false}}, \"species_id\": 70, \"name\": \"Dog\"}',NULL),
(510,'species.created',1,'petsona.helpcare@gmail.com','127.0.0.1','Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/147.0.0.0 Safari/537.36','2026-04-25 20:33:44','{\"changes\": {\"name\": {\"old\": null, \"new\": \"Cat\"}, \"description\": {\"old\": null, \"new\": \"Cats are small, independent domestic animals known for their agility, curiosity, and clean behavior. They are affectionate but also enjoy solitude, making them ideal for both active and quiet homes. Cats groom themselves regularly but still need proper feeding, litter maintenance, and vet care. They are playful yet low-maintenance pets that form strong bonds with their owners while maintaining an independent personality.\"}, \"icon\": {\"old\": null, \"new\": \"fa-solid fa-cat\"}, \"requires_exercise\": {\"old\": null, \"new\": true}, \"requires_training\": {\"old\": null, \"new\": true}, \"requires_grooming\": {\"old\": null, \"new\": true}, \"requires_enclosure\": {\"old\": null, \"new\": false}, \"predatory_species\": {\"old\": null, \"new\": true}, \"fragile_species\": {\"old\": null, \"new\": false}, \"beginner_friendly\": {\"old\": null, \"new\": true}, \"requires_permit\": {\"old\": null, \"new\": false}, \"special_vet_required\": {\"old\": null, \"new\": false}, \"has_breed\": {\"old\": null, \"new\": true}, \"abandonment_risk_level\": {\"old\": null, \"new\": \"Medium\"}, \"ethical_notes\": {\"old\": null, \"new\": \"Cats are often surrendered due to litter box issues, allergies, or underestimating their long-term care needs. They are not \\u201clow-maintenance\\u201d in all cases and still need attention, stimulation, and proper environment. Adoption should be a long-term commitment, and spaying/neutering is important to prevent overpopulation and improve behavior.\"}, \"image_url\": {\"old\": null, \"new\": \"uploads/species/cat_species.png\"}}, \"species_id\": 71, \"name\": \"Cat\"}',NULL),
(511,'species.created',1,'petsona.helpcare@gmail.com','127.0.0.1','Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/147.0.0.0 Safari/537.36','2026-04-25 20:39:17','{\"changes\": {\"name\": {\"old\": null, \"new\": \"Hamster\"}, \"description\": {\"old\": null, \"new\": \"Hamsters are small, nocturnal rodents often kept as pets. They are active at night and enjoy running, burrowing, and exploring. Most hamsters are solitary and should be housed alone in a clean cage with bedding, a wheel, and hiding spots. They eat a mix of seeds, grains, and fresh food. Hamsters are low-maintenance but need gentle handling, regular cleaning, and a safe, stress-free environment to stay healthy.\"}, \"icon\": {\"old\": null, \"new\": \"fa-solid fa-otter\"}, \"requires_exercise\": {\"old\": null, \"new\": true}, \"requires_training\": {\"old\": null, \"new\": true}, \"requires_grooming\": {\"old\": null, \"new\": true}, \"requires_enclosure\": {\"old\": null, \"new\": true}, \"predatory_species\": {\"old\": null, \"new\": false}, \"fragile_species\": {\"old\": null, \"new\": true}, \"beginner_friendly\": {\"old\": null, \"new\": true}, \"requires_permit\": {\"old\": null, \"new\": false}, \"special_vet_required\": {\"old\": null, \"new\": false}, \"has_breed\": {\"old\": null, \"new\": true}, \"abandonment_risk_level\": {\"old\": null, \"new\": \"Medium\"}, \"ethical_notes\": {\"old\": null, \"new\": \"Hamsters are often surrendered because owners underestimate their nocturnal habits, short lifespan, and need for proper enclosure setup. They require a quiet, stable environment and can be easily stressed by rough handling or noise. Responsible care includes proper cage size, enrichment, and understanding that they are not \\u201cstarter toys\\u201d but living animals with specific needs.\"}, \"image_url\": {\"old\": null, \"new\": \"uploads/species/Adorable_hamster_gathering_on_fabric_steps.png\"}}, \"species_id\": 72, \"name\": \"Hamster\"}',NULL),
(512,'species.created',1,'petsona.helpcare@gmail.com','127.0.0.1','Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/147.0.0.0 Safari/537.36','2026-04-25 20:42:41','{\"changes\": {\"name\": {\"old\": null, \"new\": \"Rabbit\"}, \"description\": {\"old\": null, \"new\": \"Rabbits are small to medium-sized herbivorous mammals known for their soft fur, long ears, and gentle nature. They are social animals that can form strong bonds with humans and other rabbits. Rabbits are active, curious, and need space to hop and explore. They eat mainly hay, fresh vegetables, and pellets. Proper care includes regular grooming, a clean living area, and social interaction to keep them healthy and happy.\"}, \"icon\": {\"old\": null, \"new\": \"fa-solid fa-otter\"}, \"requires_exercise\": {\"old\": null, \"new\": true}, \"requires_training\": {\"old\": null, \"new\": true}, \"requires_grooming\": {\"old\": null, \"new\": true}, \"requires_enclosure\": {\"old\": null, \"new\": true}, \"predatory_species\": {\"old\": null, \"new\": false}, \"fragile_species\": {\"old\": null, \"new\": true}, \"beginner_friendly\": {\"old\": null, \"new\": true}, \"requires_permit\": {\"old\": null, \"new\": false}, \"special_vet_required\": {\"old\": null, \"new\": false}, \"has_breed\": {\"old\": null, \"new\": true}, \"abandonment_risk_level\": {\"old\": null, \"new\": \"Medium\"}, \"ethical_notes\": {\"old\": null, \"new\": \"Rabbits are often misunderstood as low-maintenance pets but need space, social interaction, and daily care. Improper housing, lack of companionship, and poor diet are common issues. They are sensitive animals that can become stressed easily. Responsible ownership includes proper diet (hay-based), enrichment, spaying/neutering, and ensuring long-term commitment.\"}, \"image_url\": {\"old\": null, \"new\": \"uploads/species/rabbit_species.png\"}}, \"species_id\": 73, \"name\": \"Rabbit\"}',NULL),
(513,'species.created',1,'petsona.helpcare@gmail.com','127.0.0.1','Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/147.0.0.0 Safari/537.36','2026-04-25 20:45:40','{\"changes\": {\"name\": {\"old\": null, \"new\": \"Lovebird\"}, \"description\": {\"old\": null, \"new\": \"Lovebirds are small, social parrots known for their strong pair bonding and affectionate behavior. They are active, intelligent, and highly social birds that thrive on interaction with their owners or other lovebirds. They enjoy playing, climbing, and chewing. Lovebirds require a spacious cage, mental stimulation, and daily attention. They are vocal and can become stressed if left alone for long periods, making companionship important for their wellbeing.\"}, \"icon\": {\"old\": null, \"new\": \"fa-solid fa-dove\"}, \"requires_exercise\": {\"old\": null, \"new\": true}, \"requires_training\": {\"old\": null, \"new\": true}, \"requires_grooming\": {\"old\": null, \"new\": true}, \"requires_enclosure\": {\"old\": null, \"new\": true}, \"predatory_species\": {\"old\": null, \"new\": false}, \"fragile_species\": {\"old\": null, \"new\": false}, \"beginner_friendly\": {\"old\": null, \"new\": false}, \"requires_permit\": {\"old\": null, \"new\": false}, \"special_vet_required\": {\"old\": null, \"new\": false}, \"has_breed\": {\"old\": null, \"new\": true}, \"abandonment_risk_level\": {\"old\": null, \"new\": \"Medium\"}, \"ethical_notes\": {\"old\": null, \"new\": \"Lovebirds are highly social and can become stressed or aggressive if isolated or bored. Many are surrendered due to noise, biting, or lack of time for interaction. They need companionship, enrichment, and daily attention. Keeping them in pairs or giving strong social interaction is important for their emotional wellbeing.\"}, \"image_url\": {\"old\": null, \"new\": \"uploads/species/Colorful_lovebirds_on_tiered_platform.png\"}}, \"species_id\": 74, \"name\": \"Lovebird\"}',NULL),
(514,'species.created',1,'petsona.helpcare@gmail.com','127.0.0.1','Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/147.0.0.0 Safari/537.36','2026-04-25 20:49:00','{\"changes\": {\"name\": {\"old\": null, \"new\": \"Bettafish\"}, \"description\": {\"old\": null, \"new\": \"Betta fish (Siamese fighting fish) are small freshwater fish known for their vibrant colors and flowing fins. They are popular aquarium pets due to their beauty and personality. Bettas are territorial, especially males, and should usually be kept alone. They thrive in warm, clean water and need a properly sized tank with filtration and hiding spaces. Their diet includes pellets, frozen, or live food. With proper care, they are hardy and can live for several years.\"}, \"icon\": {\"old\": null, \"new\": \"fa-solid fa-fish\"}, \"requires_exercise\": {\"old\": null, \"new\": false}, \"requires_training\": {\"old\": null, \"new\": true}, \"requires_grooming\": {\"old\": null, \"new\": true}, \"requires_enclosure\": {\"old\": null, \"new\": true}, \"predatory_species\": {\"old\": null, \"new\": true}, \"fragile_species\": {\"old\": null, \"new\": false}, \"beginner_friendly\": {\"old\": null, \"new\": true}, \"requires_permit\": {\"old\": null, \"new\": false}, \"special_vet_required\": {\"old\": null, \"new\": false}, \"has_breed\": {\"old\": null, \"new\": false}, \"abandonment_risk_level\": {\"old\": null, \"new\": \"Medium\"}, \"ethical_notes\": {\"old\": null, \"new\": \"Betta fish are often sold as \\u201clow-maintenance bowl pets,\\u201d but this is a misconception. They need filtered, heated tanks and clean water to thrive. Poor conditions can lead to stress and illness. Males are highly territorial and must be kept alone. Responsible care includes proper tank setup, water quality management, and avoiding small containers.\"}, \"image_url\": {\"old\": null, \"new\": \"uploads/species/Colorful_betta_fish_collection_arrangement.png\"}}, \"species_id\": 75, \"name\": \"Bettafish\"}',NULL),
(515,'species.created',1,'petsona.helpcare@gmail.com','127.0.0.1','Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/147.0.0.0 Safari/537.36','2026-04-25 20:50:15','{\"changes\": {\"name\": {\"old\": null, \"new\": \"Pigeon\"}, \"description\": {\"old\": null, \"new\": \"Pigeons are medium-sized birds known for their intelligence, adaptability, and strong homing ability. They are social animals that often live in flocks and can form bonds with humans. Pigeons are hardy and can thrive in urban or rural environments. They eat seeds, grains, and small plant materials. With proper care, they can be kept as pets in spacious aviaries and require clean water, balanced nutrition, and regular health monitoring.\"}, \"icon\": {\"old\": null, \"new\": \"fa-solid fa-dove\"}, \"requires_exercise\": {\"old\": null, \"new\": true}, \"requires_training\": {\"old\": null, \"new\": true}, \"requires_grooming\": {\"old\": null, \"new\": true}, \"requires_enclosure\": {\"old\": null, \"new\": true}, \"predatory_species\": {\"old\": null, \"new\": false}, \"fragile_species\": {\"old\": null, \"new\": false}, \"beginner_friendly\": {\"old\": null, \"new\": true}, \"requires_permit\": {\"old\": null, \"new\": false}, \"special_vet_required\": {\"old\": null, \"new\": false}, \"has_breed\": {\"old\": null, \"new\": true}, \"abandonment_risk_level\": {\"old\": null, \"new\": \"Low\"}, \"ethical_notes\": {\"old\": null, \"new\": \"Pigeons are often misunderstood as \\u201cdirty\\u201d birds, but they are intelligent, social, and clean when properly cared for. They need space to fly, social interaction, and a safe environment. Poor housing and neglect can lead to stress and illness. Responsible care includes proper nutrition, hygiene, and allowing natural flock behavior when possible.\"}, \"image_url\": {\"old\": null, \"new\": \"uploads/species/Rows_of_colorful_pigeons_indoors.png\"}}, \"species_id\": 76, \"name\": \"Pigeon\"}',NULL),
(516,'breed.created',1,'petsona.helpcare@gmail.com','127.0.0.1','Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/147.0.0.0 Safari/537.36','2026-04-25 20:53:32','{\"changes\": {\"name\": {\"old\": null, \"new\": \"Siamese\"}, \"summary\": {\"old\": null, \"new\": \"The Siamese cat is a sleek, short-haired breed known for its striking blue eyes, color-point coat, and highly social personality. They are intelligent, vocal, and form strong bonds with their owners. Siamese cats are active, playful, and enjoy constant interaction. They do not like being left alone for long periods and thrive in homes where they receive attention, stimulation, and companionship.\"}, \"temperament\": {\"old\": null, \"new\": \"Affectionate, Vocal, Intelligent, Social, Energetic\"}, \"energy_level\": {\"old\": null, \"new\": \"High\"}, \"exercise_needs\": {\"old\": null, \"new\": \"High\"}, \"grooming_needs\": {\"old\": null, \"new\": \"Low\"}, \"space_needs\": {\"old\": null, \"new\": \"Medium\"}, \"trainability\": {\"old\": null, \"new\": \"Easy\"}, \"care_level\": {\"old\": null, \"new\": \"Beginner\"}, \"care_intensity\": {\"old\": null, \"new\": \"High\"}, \"time_commitment\": {\"old\": null, \"new\": \"High\"}, \"experience_required\": {\"old\": null, \"new\": \"Beginner\"}, \"environment_complexity\": {\"old\": null, \"new\": \"Simple\"}, \"handling_tolerance\": {\"old\": null, \"new\": \"Medium\"}, \"noise_level\": {\"old\": null, \"new\": \"Loud\"}, \"social_needs\": {\"old\": null, \"new\": \"High\"}, \"compatibility_risk\": {\"old\": null, \"new\": \"Medium\"}, \"prey_drive\": {\"old\": null, \"new\": \"Medium\"}, \"lifespan\": {\"old\": null, \"new\": \"12\\u201320 years\"}, \"care_cost\": {\"old\": null, \"new\": \"3,000\\u20138,000 PHP/month (approx.)\"}, \"allergy_friendly\": {\"old\": null, \"new\": false}, \"dog_friendly\": {\"old\": null, \"new\": true}, \"cat_friendly\": {\"old\": null, \"new\": true}, \"small_pet_friendly\": {\"old\": null, \"new\": false}, \"child_friendly\": {\"old\": null, \"new\": true}, \"senior_friendly\": {\"old\": null, \"new\": false}, \"preventive_care_level\": {\"old\": null, \"new\": \"Medium\"}, \"emergency_care_risk\": {\"old\": null, \"new\": \"Low\"}, \"stress_sensitivity\": {\"old\": null, \"new\": \"Medium\"}, \"monthly_cost_level\": {\"old\": null, \"new\": \"Medium\"}, \"lifetime_cost_level\": {\"old\": null, \"new\": \"High\"}, \"image_url\": {\"old\": null, \"new\": \"uploads/breeds/siamese.png\"}}, \"species_id\": 71, \"breed_id\": 6, \"breed_name\": \"Siamese\"}',NULL),
(517,'breed.created',1,'petsona.helpcare@gmail.com','127.0.0.1','Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/147.0.0.0 Safari/537.36','2026-04-25 20:55:18','{\"changes\": {\"name\": {\"old\": null, \"new\": \"Himalayan\"}, \"summary\": {\"old\": null, \"new\": \"The Himalayan cat is a long-haired breed created by crossing Persian and Siamese cats. It has a fluffy coat, flat face, and striking blue eyes with color-point markings. Himalayans are calm, affectionate, and enjoy quiet indoor living. They are people-oriented but less active, preferring relaxed companionship over high energy play. They require regular grooming due to their long coat.\"}, \"temperament\": {\"old\": null, \"new\": \"Calm, Gentle, Affectionate, Quiet, Friendly\"}, \"energy_level\": {\"old\": null, \"new\": \"Low\"}, \"exercise_needs\": {\"old\": null, \"new\": \"Low\"}, \"grooming_needs\": {\"old\": null, \"new\": \"High\"}, \"space_needs\": {\"old\": null, \"new\": \"Medium\"}, \"trainability\": {\"old\": null, \"new\": \"Moderate\"}, \"care_level\": {\"old\": null, \"new\": \"Beginner\"}, \"care_intensity\": {\"old\": null, \"new\": \"Medium\"}, \"time_commitment\": {\"old\": null, \"new\": \"Medium\"}, \"experience_required\": {\"old\": null, \"new\": \"Beginner\"}, \"environment_complexity\": {\"old\": null, \"new\": \"Simple\"}, \"handling_tolerance\": {\"old\": null, \"new\": \"High\"}, \"noise_level\": {\"old\": null, \"new\": \"Low\"}, \"social_needs\": {\"old\": null, \"new\": \"Medium\"}, \"compatibility_risk\": {\"old\": null, \"new\": \"High\"}, \"prey_drive\": {\"old\": null, \"new\": \"Low\"}, \"lifespan\": {\"old\": null, \"new\": \"9\\u201315 years\"}, \"care_cost\": {\"old\": null, \"new\": \"5,000\\u201312,000 PHP/month (approx.)\"}, \"allergy_friendly\": {\"old\": null, \"new\": false}, \"dog_friendly\": {\"old\": null, \"new\": true}, \"cat_friendly\": {\"old\": null, \"new\": true}, \"small_pet_friendly\": {\"old\": null, \"new\": true}, \"child_friendly\": {\"old\": null, \"new\": true}, \"senior_friendly\": {\"old\": null, \"new\": false}, \"preventive_care_level\": {\"old\": null, \"new\": \"High\"}, \"emergency_care_risk\": {\"old\": null, \"new\": \"Low\"}, \"stress_sensitivity\": {\"old\": null, \"new\": \"Medium\"}, \"monthly_cost_level\": {\"old\": null, \"new\": \"High\"}, \"lifetime_cost_level\": {\"old\": null, \"new\": \"High\"}, \"image_url\": {\"old\": null, \"new\": \"uploads/breeds/himalayan.png\"}}, \"species_id\": 71, \"breed_id\": 7, \"breed_name\": \"Himalayan\"}',NULL),
(518,'breed.created',1,'petsona.helpcare@gmail.com','127.0.0.1','Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/147.0.0.0 Safari/537.36','2026-04-25 20:56:34','{\"changes\": {\"name\": {\"old\": null, \"new\": \"Russian Blue\"}, \"summary\": {\"old\": null, \"new\": \"The Russian Blue is a short-haired cat breed known for its elegant silver-blue coat and bright green eyes. It is intelligent, quiet, and very loyal to its owners. Russian Blues are gentle and slightly reserved with strangers but form strong bonds with their family. They are clean, low-odor cats and are generally well-behaved, making them great indoor pets.\"}, \"temperament\": {\"old\": null, \"new\": \"Gentle, Quiet, Intelligent, Loyal, Shy with Strangers\"}, \"energy_level\": {\"old\": null, \"new\": \"Medium\"}, \"exercise_needs\": {\"old\": null, \"new\": \"Medium\"}, \"grooming_needs\": {\"old\": null, \"new\": \"Low\"}, \"space_needs\": {\"old\": null, \"new\": \"Medium\"}, \"trainability\": {\"old\": null, \"new\": \"Easy\"}, \"care_level\": {\"old\": null, \"new\": \"Beginner\"}, \"care_intensity\": {\"old\": null, \"new\": \"Medium\"}, \"time_commitment\": {\"old\": null, \"new\": \"Medium\"}, \"experience_required\": {\"old\": null, \"new\": \"Beginner\"}, \"environment_complexity\": {\"old\": null, \"new\": \"Simple\"}, \"handling_tolerance\": {\"old\": null, \"new\": \"Medium\"}, \"noise_level\": {\"old\": null, \"new\": \"Low\"}, \"social_needs\": {\"old\": null, \"new\": \"Medium\"}, \"compatibility_risk\": {\"old\": null, \"new\": \"High\"}, \"prey_drive\": {\"old\": null, \"new\": \"Medium\"}, \"lifespan\": {\"old\": null, \"new\": \"15\\u201320 years\"}, \"care_cost\": {\"old\": null, \"new\": \"3,000\\u20137,000 PHP/month (approx.)\"}, \"allergy_friendly\": {\"old\": null, \"new\": true}, \"dog_friendly\": {\"old\": null, \"new\": true}, \"cat_friendly\": {\"old\": null, \"new\": true}, \"small_pet_friendly\": {\"old\": null, \"new\": false}, \"child_friendly\": {\"old\": null, \"new\": true}, \"senior_friendly\": {\"old\": null, \"new\": false}, \"preventive_care_level\": {\"old\": null, \"new\": \"Medium\"}, \"emergency_care_risk\": {\"old\": null, \"new\": \"Low\"}, \"stress_sensitivity\": {\"old\": null, \"new\": \"Medium\"}, \"monthly_cost_level\": {\"old\": null, \"new\": \"Medium\"}, \"lifetime_cost_level\": {\"old\": null, \"new\": \"High\"}, \"image_url\": {\"old\": null, \"new\": \"uploads/breeds/russian_blue.png\"}}, \"species_id\": 71, \"breed_id\": 8, \"breed_name\": \"Russian Blue\"}',NULL),
