/*Table structure for table `breed` */

DROP TABLE IF EXISTS `breed`;

CREATE TABLE `breed` (
  `id` int NOT NULL AUTO_INCREMENT,
  `species_id` int NOT NULL,
  `name` varchar(100) NOT NULL,
  `summary` text NOT NULL,
  `temperament` varchar(255) DEFAULT NULL,
  `image_url` varchar(255) NOT NULL,
  `energy_level` enum('Low','Medium','High') DEFAULT NULL,
  `exercise_needs` enum('Low','Medium','High') DEFAULT NULL,
  `grooming_needs` enum('Low','Medium','High') DEFAULT NULL,
  `space_needs` enum('Small','Medium','Large') DEFAULT NULL,
  `trainability` enum('Easy','Moderate','Difficult') DEFAULT NULL,
  `handling_tolerance` enum('Low','Medium','High') DEFAULT NULL,
  `noise_level` enum('Silent','Low','Moderate','Loud') DEFAULT NULL,
  `social_needs` enum('Low','Medium','High') DEFAULT NULL,
  `prey_drive` enum('None','Low','Medium','High') NOT NULL,
  `care_intensity` enum('Low','Medium','High') DEFAULT NULL,
  `time_commitment` enum('Low','Medium','High') DEFAULT NULL,
  `experience_required` enum('Beginner','Intermediate','Advanced') DEFAULT NULL,
  `environment_complexity` enum('Simple','Moderate','Complex') DEFAULT NULL,
  `compatibility_risk` enum('Low','Medium','High') DEFAULT NULL,
  `preventive_care_level` enum('Low','Medium','High') DEFAULT NULL COMMENT 'Frequency of vet visits, vaccines, parasite control',
  `common_health_issues` text COMMENT 'Breed-typical health issues vets warn about',
  `emergency_care_risk` enum('Low','Medium','High') DEFAULT NULL COMMENT 'Likelihood of emergency or sudden medical costs',
  `stress_sensitivity` enum('Low','Medium','High') DEFAULT NULL COMMENT 'How easily the pet becomes stressed by change',
  `monthly_cost_level` enum('Low','Medium','High') DEFAULT NULL COMMENT 'Food, grooming, routine care',
  `lifetime_cost_level` enum('Low','Medium','High') DEFAULT NULL COMMENT 'Expected long-term financial commitment',
  `care_cost` varchar(255) DEFAULT NULL COMMENT 'Estimated average annual care cost',
  `lifespan` varchar(50) DEFAULT NULL COMMENT 'Average life expectancy',
  `allergy_friendly` tinyint(1) DEFAULT NULL COMMENT 'Suitable for allergy-sensitive owners',
  `child_friendly` tinyint(1) DEFAULT NULL COMMENT 'Safe and tolerant around children',
  `senior_friendly` tinyint(1) DEFAULT NULL COMMENT 'Suitable for elderly owners',
  `dog_friendly` tinyint(1) DEFAULT NULL,
  `cat_friendly` tinyint(1) DEFAULT NULL,
  `small_pet_friendly` tinyint(1) DEFAULT NULL,
  `min_enclosure_size` varchar(100) DEFAULT NULL COMMENT 'Minimum recommended enclosure size for the breed',
  `heart_vote_count` int DEFAULT NULL COMMENT 'Total heart votes from all users',
  `is_active` tinyint(1) DEFAULT NULL,
  `deleted_at` datetime DEFAULT NULL,
  `created_at` datetime DEFAULT NULL,
  `updated_at` datetime DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `species_id` (`species_id`),
  KEY `ix_breed_name` (`name`),
  CONSTRAINT `breed_ibfk_1` FOREIGN KEY (`species_id`) REFERENCES `species` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=31 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

